        public STAGE ensureCloseSink() {
            this.closeSink = true;
            return me();
        }


        public STAGE encoding(Charset charset) {
            this.charset = $.requireNotNull(charset);
            return me();
        }


        public int to(Writer sink) {
            try {
                return doWriteTo(sink);
            } catch (IOException e) {
                throw E.ioException(e);
            } finally {
                if (closeSink) {
                    close(sink);
                } else {
                    flush(sink);
                }
            }
        }


        public int to(OutputStream sink) {
            try {
                return doWriteTo(sink);
            } catch (IOException e) {
                throw E.ioException(e);
            } finally {
                if (closeSink) {
